    this.childId = this.route.snapshot.paramMap.get('childId');
    if (!this.childId) {
      this.snackBar.open('Ingen barn ID fundet', 'Luk', {
        duration: 3000
      });
      this.router.navigate(['/dashboard']);
      return;
    }
    // Subscribe to current family
    this.subscriptions.add(this.familyService.currentFamily$.subscribe(family => {
      this.currentFamily = family;
      if (family) {
        this.loadChildData();
      }
    }));
    // Subscribe to balance animation events
    this.subscriptions.add(this.balanceAnimationService.animationEvents$.subscribe(event => {
      if (event.childId === this.childId) {
        this.handleBalanceAnimationEvent(event);
      }
    }));
